fn validate_async_commitment_call(
    async_call: &BasicAsyncCallResult,
) -> Result<ritual_precompile_codecs::DecodedPrecompileData, String> {
    async_commitment_metadata(async_call.precompile_address, "detected async precompile")?;

    let input = async_call.input.as_ref();
    validate_async_payload(async_call.precompile_address, input, MAX_SHORT_ASYNC_TTL_BLOCKS)
        .map_err(|err| format!("invalid async commitment payload: {err}"))?;

    try_decode_precompile_data(async_call.precompile_address, input)
        .map_err(|err| format!("malformed async commitment input: {err}"))
}

fn validate_commitment_structure(
    commitment: &TxAsyncCommitment,
) -> Result<&'static AsyncPrecompileMetadata, BlockVerificationError> {
    if commitment.ttl == 0 || commitment.ttl > MAX_SHORT_ASYNC_TTL_BLOCKS {
        return Err(BlockVerificationError::InvalidAsyncCommitment(format!(
            "TTL {} outside async commitment bounds 1..={}",
            commitment.ttl, MAX_SHORT_ASYNC_TTL_BLOCKS
        )));
    }
    let metadata = async_commitment_metadata(commitment.precompile_address, "async commitment")
        .map_err(BlockVerificationError::InvalidAsyncCommitment)?;
    if commitment.executor_address.is_zero() {
        return Err(BlockVerificationError::InvalidAsyncCommitment(
            "executor address cannot be zero".to_string(),
        ));
    }
    validate_async_payload(
        commitment.precompile_address,
        commitment.precompile_input.as_ref(),
        MAX_SHORT_ASYNC_TTL_BLOCKS,
    )?;
    let decoded = try_decode_precompile_data(commitment.precompile_address, commitment.precompile_input.as_ref())?;
    if decoded.executor != commitment.executor_address { /* reject */ }
    if decoded.ttl != commitment.ttl { /* reject */ }
